  aircraft_id = VALUES(aircraft_id),
  bom_node_id = VALUES(bom_node_id),
  part_instance_id = VALUES(part_instance_id),
  data_domain = VALUES(data_domain),
  source_system = VALUES(source_system),
  source_table = VALUES(source_table),
  source_record_id = VALUES(source_record_id),
  source_record_key = VALUES(source_record_key),
  relation_type = VALUES(relation_type),
  required_flag = VALUES(required_flag),
  included_flag = VALUES(included_flag),
  validity_status = VALUES(validity_status),
  summary = VALUES(summary),
  attrs_json = JSON_MERGE_PATCH(COALESCE(attrs_json, JSON_OBJECT()), VALUES(attrs_json));

-- Verification
SELECT 'excel_demo_context_nodes' AS item, COUNT(*) AS count
FROM t1_aircraft_bom_node
WHERE created_by = 'codex-excel-demo'
   OR remark LIKE 'Excel demo context node;%';

SELECT parent_id, node_level, node_type, COUNT(*) AS count
FROM t1_aircraft_bom_node
WHERE created_by = 'codex-excel-demo'
GROUP BY parent_id, node_level, node_type
ORDER BY node_level, node_type;

SELECT 'profile_links' AS item, COUNT(*) AS count
FROM t1_product_object_profile
WHERE JSON_UNQUOTE(JSON_EXTRACT(attrs_json, '$.focusContext')) = 'hydraulic_landing_gear_context';
